# national and international regexes are matched against the phone number with all whitespace and
# common delimiters (`-`, `.`, `(`, `)`) removed
_COUNTRY_PHONE_PATTERNS = {
    'US': {
        'national': re.compile(r'^\d{10}$'),
        'international': re.compile(r'^\+1\d{10}$'),
    },
    'GB': {
        'national': re.compile(r'^0\d{9,10}$'),
        'international': re.compile(r'^\+44\d{9,10}$'),
    },
}

_GENERIC_INTERNATIONAL_PHONE_PATTERN = re.compile(r'^\+[1-9]\d{6,14}$')
_GENERIC_NATIONAL_PHONE_PATTERN = re.compile(r'^\d{7,15}$')


class IsPhoneNumber(DirtyEquals[str]):
    """
    A class that checks if a value is a valid phone number, optionally restricted to a specific country.
    """

    def __init__(self, country: Optional[str] = None):
        """
        Args:
            country: The ISO 3166-1 alpha-2 country code to validate against (e.g. `'US'`, `'GB'`), if omitted,
                generic phone number validation is used.

        !!! note
            This provides pragmatic, "good enough" validation for common phone number formats, it is not a
            substitute for a full phone number validation library like
            [phonenumbers](https://github.com/daviddrysdale/python-phonenumbers).

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber
        assert 'not a phone number' != IsPhoneNumber
        assert 123 != IsPhoneNumber

        assert '555-123-4567' == IsPhoneNumber('US')
        assert '+1-555-123-4567' == IsPhoneNumber('US')
        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+44 20 7946 0958' == IsPhoneNumber('GB')
        assert '020 7946 0958' != IsPhoneNumber('US')
        assert '555-123-4567' != IsPhoneNumber('GB')
        ```
        """
        self.country = country
        super().__init__(country or plain_repr('*'))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        cleaned = re.sub(r'[\s\-.()]', '', other)
        if not re.fullmatch(r'\+?\d+', cleaned):
            return False

        country = self.country.upper() if self.country else None
        patterns = _COUNTRY_PHONE_PATTERNS.get(country) if country else None

        if patterns is None:
            if country is not None:
                # unknown country, fall back to generic international validation only
                return cleaned.startswith('+') and bool(_GENERIC_INTERNATIONAL_PHONE_PATTERN.fullmatch(cleaned))
            elif cleaned.startswith('+'):
                return bool(_GENERIC_INTERNATIONAL_PHONE_PATTERN.fullmatch(cleaned))
            else:
                return bool(_GENERIC_NATIONAL_PHONE_PATTERN.fullmatch(cleaned))
        elif cleaned.startswith('+'):
            return bool(patterns['international'].fullmatch(cleaned))
        else:
            return bool(patterns['national'].fullmatch(cleaned))"}

